<html lang="ar" dir="rtl">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0, user-scalable=no">
<title>مغامرة ناصر 3D</title>
<style>
* { margin:0; padding:0; box-sizing:border-box; }
body { background:#000; overflow:hidden; font-family:Arial,sans-serif; }
canvas { display:block; }
#ui {
  position:fixed; top:0; left:0; width:100%;
  pointer-events:none; z-index:10;
}
#score-bar {
  display:flex; justify-content:space-between; align-items:center;
  padding:10px 20px;
  background:linear-gradient(180deg,rgba(0,0,0,0.8) 0%,transparent 100%);
  color:#fff; font-size:16px; font-weight:bold;
}
#score-bar span { text-shadow:0 0 10px #00ffff; }
#health-bar-container {
  width:130px; height:14px;
  background:rgba(255,255,255,0.2);
  border-radius:7px; overflow:hidden;
  border:1px solid #fff;
}
#health-bar {
  height:100%; width:100%;
  background:linear-gradient(90deg,#ff4444,#ff0000);
  transition:width 0.3s;
  border-radius:7px;
}
#level-text {
  position:fixed; top:60px; left:50%;
  transform:translateX(-50%);
  color:#ffd700; font-size:15px; font-weight:bold;
  text-shadow:0 0 10px #ffd700;
  pointer-events:none; z-index:10;
}
/* Mobile Controls */
#mobile-controls {
  position:fixed; bottom:0; left:0; width:100%;
  height:200px; z-index:20; pointer-events:none;
}
#joystick-area {
  position:absolute; bottom:20px; left:20px;
  width:130px; height:130px; pointer-events:all;
}
#joystick-base {
  width:130px; height:130px;
  background:rgba(255,255,255,0.12);
  border:3px solid rgba(255,255,255,0.35);
  border-radius:50%; position:relative;
}
#joystick-thumb {
  width:52px; height:52px;
  background:radial-gradient(circle,#00ffff,#0055ff);
  border-radius:50%;
  position:absolute; top:50%; left:50%;
  transform:translate(-50%,-50%);
  box-shadow:0 0 18px #00ffff;
  pointer-events:none;
}
#action-buttons {
  position:absolute; bottom:20px; right:20px;
  display:grid;
  grid-template-columns:65px 65px;
  grid-template-rows:65px 65px;
  gap:10px; pointer-events:all;
}
.action-btn {
  width:65px; height:65px;
  border-radius:50%;
  border:3px solid rgba(255,255,255,0.5);
  font-size:24px; font-weight:bold;
  cursor:pointer;
  display:flex; align-items:center; justify-content:center;
  user-select:none; -webkit-user-select:none;
  transition:transform 0.1s,opacity 0.1s;
  pointer-events:all;
  -webkit-tap-highlight-color:transparent;
}
.action-btn:active { transform:scale(0.85); opacity:0.8; }
#btn-jump {
  background:radial-gradient(circle,#ffdd00,#ff8800);
  box-shadow:0 0 18px #ffaa00;
  grid-column:2; grid-row:1;
}
#btn-attack {
  background:radial-gradient(circle,#ff4444,#cc0000);
  box-shadow:0 0 18px #ff0000;
  grid-column:1; grid-row:2;
}
#btn-dash {
  background:radial-gradient(circle,#44ff88,#00aa44);
  box-shadow:0 0 18px #00ff66;
  grid-column:2; grid-row:2;
}
#btn-camera-left {
  position:absolute; bottom:80px; left:165px;
  width:50px; height:50px;
  border-radius:50%;
  background:rgba(150,100,255,0.7);
  border:2px solid rgba(255,255,255,0.4);
  font-size:20px;
  display:flex; align-items:center; justify-content:center;
  cursor:pointer; pointer-events:all;
  user-select:none;
}
#btn-camera-right {
  position:absolute; bottom:80px; right:155px;
  width:50px; height:50px;
  border-radius:50%;
  background:rgba(150,100,255,0.7);
  border:2px solid rgba(255,255,255,0.4);
  font-size:20px;
  display:flex; align-items:center; justify-content:center;
  cursor:pointer; pointer-events:all;
  user-select:none;
}
/* Overlays */
.overlay {
  position:fixed; top:0; left:0; width:100%; height:100%;
  background:rgba(0,0,0,0.88);
  display:flex; flex-direction:column;
  align-items:center; justify-content:center;
  z-index:100; color:#fff;
}
.overlay h1 {
  font-size:38px;
  background:linear-gradient(90deg,#00ffff,#ff00ff,#ffff00);
  -webkit-background-clip:text;
  -webkit-text-fill-color:transparent;
  margin-bottom:10px; text-align:center;
  padding:0 20px;
}
.overlay p { font-size:16px; color:#aaa; margin-bottom:20px; text-align:center; padding:0 20px; }
.overlay button {
  padding:15px 45px;
  font-size:20px; border:none;
  border-radius:40px;
  background:linear-gradient(90deg,#00ffff,#0055ff);
  color:#fff; cursor:pointer; font-weight:bold;
  box-shadow:0 0 25px #00aaff;
  margin:8px;
  transition:transform 0.15s;
  -webkit-tap-highlight-color:transparent;
}
.overlay button:active { transform:scale(0.92); }
#game-over-screen { display:none; }
#win-screen { display:none; }
</style>
</head>
<body>

<canvas id="gameCanvas"></canvas>

<div id="ui">
  <div id="score-bar">
    <span>⭐ <span id="score">0</span></span>
    <span>🦸 ناصر</span>
    <div>
      <div style="font-size:11px;color:#aaa;margin-bottom:3px;">❤️ الصحة</div>
      <div id="health-bar-container"><div id="health-bar"></div></div>
    </div>
  </div>
</div>
<div id="level-text">🌟 المرحلة 1 - اجمع 10 نجوم!</div>

<!-- Mobile Controls -->
<div id="mobile-controls">
  <div id="joystick-area">
    <div id="joystick-base"><div id="joystick-thumb"></div></div>
  </div>
  <div id="btn-camera-left">◀</div>
  <div id="btn-camera-right">▶</div>
  <div id="action-buttons">
    <div class="action-btn" id="btn-jump">⬆</div>
    <div class="action-btn" id="btn-attack">⚔</div>
    <div class="action-btn" id="btn-dash">💨</div>
  </div>
</div>

<!-- Start Screen -->
<div class="overlay" id="start-screen">
  <h1>🦸 مغامرة ناصر 3D</h1>
  <p>ساعد ناصر في جمع النجوم وهزيمة الأعداء!</p>
  <p style="font-size:13px;color:#555;">🕹 جويستيك للتحرك | ⬆ قفز | ⚔ هجوم | 💨 اندفاع | ◀▶ كاميرا</p>
  <button onclick="startGame()">🎮 ابدأ اللعبة</button>
</div>

<!-- Game Over -->
<div class="overlay" id="game-over-screen">
  <h1>💀 انتهت اللعبة!</h1>
  <p id="go-msg"></p>
  <button onclick="restartGame()">🔄 العب مجدداً</button>
</div>

<!-- Win -->
<div class="overlay" id="win-screen">
  <h1>🏆 أحسنت يا ناصر!</h1>
  <p id="win-msg"></p>
  <button onclick="restartGame()">🔄 العب مجدداً</button>
</div>

<script>
